class Provider {
    getSettings() {
        return {
            supportsAdult: false
        };
    }

    async search(opts) {
        try {
            if (opts.media && opts.media.mediaType !== "movie") {
                return [];
            }

            console.log("YTS: Searching for: " + opts.query);
            const query = opts.query || "";
            let searchQuery = query;
            if (opts.media && opts.media.releaseYear) {
                searchQuery += " " + opts.media.releaseYear;
            }

            const url = "https://movies-api.accel.li/api/v2/list_movies.json?query_term=" + encodeURIComponent(searchQuery);
            console.log("YTS: Fetching URL: " + url);

            const res = await fetch(url);
            if (!res.ok) {
                throw new Error("HTTP error " + res.status);
            }

            const data = await res.json();
            if (data.status !== "ok" || !data.data || !data.data.movies || data.data.movies.length === 0) {
                console.log("YTS: No movies found");
                return [];
            }

            const results = [];
            for (const movie of data.data.movies) {
                if (!movie.torrents) continue;

                for (const torrent of movie.torrents) {
                    const name = movie.title_long + " [" + torrent.quality + "] [" + (torrent.type || "").toUpperCase() + "] [YTS]";
                    let magnetLink = "";
                    if (torrent.hash) {
                        magnetLink = "magnet:?xt=urn:btih:" + torrent.hash + "&dn=" + encodeURIComponent(name) +
                            "&tr=udp://tracker.coppersurfer.tk:6969/announce" +
                            "&tr=udp://9.rarbg.to:2710/announce" +
                            "&tr=udp://tracker.opentrackr.org:1337" +
                            "&tr=udp://tracker.internetwarriors.net:1337/announce" +
                            "&tr=udp://open.demonii.com:1337/announce" +
                            "&tr=udp://tracker.openbittorrent.com:80/announce" +
                            "&tr=udp://tracker.leechers-paradise.org:6969/announce" +
                            "&tr=udp://coppersurfer.tk:6969/announce";
                    }

                    results.push({
                        name: name,
                        date: new Date((torrent.date_uploaded_unix || 0) * 1000).toISOString(),
                        size: torrent.size_bytes || 0,
                        formattedSize: torrent.size || "",
                        seeders: torrent.seeds || 0,
                        leechers: torrent.peers || 0,
                        downloadCount: 0,
                        link: movie.url || "",
                        downloadUrl: torrent.url || "",
                        magnetLink: magnetLink,
                        infoHash: torrent.hash || "",
                        resolution: torrent.quality || "",
                        confirmed: true
                    });
                }
            }

            console.log("YTS: Found " + results.length + " torrents");
            return results;
        } catch (error) {
            console.error("YTS search failed: " + error.message);
            return [];
        }
    }

    getTorrentInfoHash(torrent) {
        return torrent.infoHash || "";
    }

    getTorrentMagnetLink(torrent) {
        return torrent.magnetLink || "";
    }
}
